xinshengLayout:
# 🌸 手账风 · 攻略日记

@particles sakura 18

@header charImage charName .fadeInDown

@quote innerVoice .fadeInUp.delay100

@row 2
  @card "🌡️ 身体信号"
    @grid 2
      temperature:stat "体温"
      moodDelta:badge "波动"
    @ring emotionLevel "心情指数" .glow
  @endcard

  @card "📅 今日手账"
    @text currentDate
    @text dayOfWeek
    @badge bondDays " 天相伴"
  @endcard
@endrow

@divider

# 📖 原著 · 命运线
@row 2
  @card "🎭 原著当前"
    @text story_current
  @endcard
  @card "⚠️ 原著下一步"
    @text story_next
  @endcard
@endrow

@divider

# 💰 事业进度
@text wallet
@grid 3
  main_task:stat "主线"
  sub1_task:stat "支线1"
  sub2_task:stat "支线2"
@text main_reward
@text sub1_reward
@text sub2_reward
@text system_771 .shimmer

@divider

# 💕 攻略目标 · 强制任务
@row 2
  @card "🎯 target1_name"
    @badge target1_avatar ""
    @badge target1_mood_emoji ""
    @text target1_mood_text
    @text target1_thought
    @ring target1_favorability "好感度" .glow
    @list
      target1_tasks
    @quote target1_comment
  @endcard

  @card "🎯 target2_name"
    @badge target2_avatar ""
    @badge target2_mood_emoji ""
    @text target2_mood_text
    @text target2_thought
    @ring target2_favorability "好感度" .glow
    @list
      target2_tasks
    @quote target2_comment
  @endcard
@endrow

@footer "✎ 糯嘰機手账 · 强行攻略日记" .fadeIn.delay500
@toggle 1
